export function jzLookup(type, wCm, lCm){
  var tbl=JZ[type];
  if(!tbl)return null;
  var ws=Object.keys(tbl).map(Number).sort(function(a,b){return a-b;});
  var ls=Object.keys(tbl[ws[0]]).map(Number).sort(function(a,b){return a-b;});
  var w=ws.find(function(x){return x>=wCm;})||ws[ws.length-1];
  var l=ls.find(function(x){return x>=lCm;})||ls[ls.length-1];
  return tbl[w]&&tbl[w][l]?{price:tbl[w][l],w:w,l:l}:null;
}

