// Lookup helper for Shadow: nearest-higher width AND height
export function rsShadowLookup(grupaCen, wCm, hCm){
  var tbl={C:RS_C,D:RS_D,E:RS_E}[grupaCen];
  if(!tbl)return null;
  var wi=RS_WIDTHS.findIndex(function(w){return w>=wCm;});
  if(wi<0)wi=RS_WIDTHS.length-1;
  var hi=RS_HEIGHTS.findIndex(function(h){return h>=hCm;});
  if(hi<0)hi=RS_HEIGHTS.length-1;
  var row=tbl[hi];
  if(!row||row[wi]==null)return null;
  return {price:row[wi], widthUsed:RS_WIDTHS[wi], heightUsed:RS_HEIGHTS[hi]};
}
export function rsSuppLookup(tbl,wCm){
  var wi=RS_SUPP_WIDTHS.findIndex(function(w){return w>=wCm;});
  if(wi<0)wi=RS_SUPP_WIDTHS.length-1;
  var keys=Object.keys(tbl).map(Number).sort(function(a,b){return a-b;});
  return tbl[keys[wi]]||tbl[keys[keys.length-1]]||0;
}
