export function rrzLookup(brand, model, wCm){
  var tbl = brand==="somfy" ? RRZ_SOMFY : RRZ_PREMIUM;
  var row = tbl[model];
  if(!row) return null;
  var idx = RRZ_WIDTHS.findIndex(function(w){ return w >= wCm; });
  if(idx<0) idx = RRZ_WIDTHS.length-1;
  var price = row[idx];
  if(price==null) return null;
  return {price: price, upToWidth: RRZ_WIDTHS[idx]};
}

export function lookup(val,obj){
  var keys=Object.keys(obj).map(Number).sort(function(a,b){return a-b;});
  var k=keys.find(function(k){return k>=val;})||keys[keys.length-1];
  return {p:obj[k],k:k};
}

export function calc(p){
  var c=p.c||{},par=p.par||{};
  var fabP=p.fabMan!=null?p.fabMan:(p.fabP!=null?p.fabP:null);
  var fabW=p.fabW||0;
  var total=0,lines=[],warn=null;

  if(p.type==="zaslona"||p.type==="firana"){
    var wCm=par.wCm||0,hCm=par.hCm||0;
    var belka=fabW,mars=+(c.mars||"1.5"),szycie=(c.sz==="wave"||c.model==="wave")?110:100;
    var dekro=c.dekro==="tak",hM=hCm/100;
    var podszewka=c.podszewka==="tak";
    if(!wCm||!(p.panels||[]).length||fabP==null)return{total:0,lines:[],warn:fabP==null&&wCm?"Wybierz tkanin\u0119":null};
    var useA2=belka>0&&hCm+20>belka;
    (p.panels||[]).forEach(function(pn){
      var pw=pn.w||0;if(!pw){lines.push(pn.side+": wpisz szerokość (cm)");return;}var pwZ=pw+20,pm=pwZ/100,z,kt,ks,kp,koszt;
      if(useA2){
        var pg=Math.ceil((belka/mars)/10)*10-20,lp=Math.ceil(pwZ/pg);
        z=+(lp*hM+0.2).toFixed(2);kt=+(z*fabP).toFixed(2);
        var sv=hM<=3?100:hM<=3.7?130:hM<=4.9?170:230;
        ks=dekro?+(z*sv).toFixed(2):+(lp*250).toFixed(2);
      }else{
        z=+(pm*mars+0.2).toFixed(2);kt=+(z*fabP).toFixed(2);
        var sv2=hM<=3?100:hM<=3.7?130:hM<=4.9?170:230;
        ks=dekro?+(z*sv2).toFixed(2):+(z*szycie).toFixed(2);
      }
      kp=podszewka?+(z*80+ks*0.5).toFixed(2):0;
      koszt=kt+ks+kp;total+=koszt;
      lines.push(pn.side+" "+pw+"cm \u00b7 "+z+"mb \u2192 "+koszt.toFixed(2).replace(".",",")+" z\u0142"+(podszewka?" (w tym podszewka)":""));
    });
  }else if(p.type==="zaluzja"){
    var wCm=par.wCm||0,lCm=par.lCm||0;
    var jt=c.jt||"al25";
    if(!wCm||!lCm)return{total:0,lines:[],warn:null};
    var res=jzLookup(jt,wCm,lCm);
    if(!res)return{total:0,lines:[],warn:"Wymiary poza zakresem cennika."};
    total=res.price;
    // dopłaty
    if(c.bezinw==="tak"){
      var bDop;
      if(jt==="al50")bDop=85.03;
      else if(jt==="al25"||jt==="al35")bDop=74.73;
      else bDop=57.12; // drewnopodobne: ba35,ba50,ba65,bs35,bs50,bs65
      total+=bDop;
      lines.push("Monta\u017c bezinwazyjny +"+bDop.toFixed(2)+" z\u0142");
    }
    if(c.tasiemka==="tak"){
      var tDop=46.43;
      if(wCm<60){warn=(warn?warn+" | ":"")+"Tasiemka niedostępna dla szer. < 60 cm.";c.tasiemka=undefined;}
      else{total+=tDop;lines.push("Dodatkowa tasiemka +"+tDop.toFixed(2)+" z\u0142");}
    }
    lines.push(JZ_LABELS[jt]+" "+wCm+"\xd7"+lCm+"cm \u2192 "+res.price+" z\u0142");
    // strefy
    var pow=(wCm/100)*(lCm/100);
    var z=JZ_ZONES[jt]||{};
    if(z.blue&&pow>=z.blue)warn="Strefa niebieska ("+pow.toFixed(2)+"m\xb2) \u2014 wymagana obs\u0142uga elektryczna.";
    else if(z.red&&pow>=z.red)warn="Strefa czerwona ("+pow.toFixed(2)+"m\xb2) \u2014 ograniczona gwarancja.";
    if(c.jzMode==="auto"){
      var mot=JZALUZJA_MOTORS.find(function(m){return m.id===c.jzMotorId;});
      var rem=JZALUZJA_REMOTES.find(function(r){return r.id===c.jzRemoteId;});
      if(mot){total+=mot.price;lines.push("Silnik: "+mot.label+" +"+mot.price.toFixed(2)+" zł");}
      if(rem){total+=rem.price;lines.push("Pilot: "+rem.label+" +"+rem.price.toFixed(2)+" zł");}
    }
  }else if(p.type==="roleta"){
    var wCm=par.wCm||0,hCm=par.hCm||0;
    if(!wCm||!hCm)return{total:0,lines:[],warn:null};
    // Nowy system: c.rModel (relax/print/back/podszewka/front/cascade/duo)
    var rModel=c.rModel||null;
    if(!rModel)return{total:0,lines:[],warn:"Wybierz model rolety"};
    var rb=c.rb==="tak"?11:0;
    var tkan=fabP!=null?fabP:160;
    var pow=parseFloat(((wCm/100)*(hCm/100)).toFixed(3));
    var rr;
    if(rModel==="duo"){
      // Duo: dwie tkaniny, mnożone x2
      rr=lookup(wCm,RDUO);
      total=parseFloat((rr.p*2+rb).toFixed(2))+parseFloat((pow*(200+tkan)*2).toFixed(2));
      lines.push("Roleta Duo "+wCm+"\xd7"+hCm+"cm \xb7 "+pow+"m\xb2 (x2 tkaniny)");
    }else{
      // Wszystkie inne: jednolita logika 200zł/m² szycie + tkanina
      rr=lookup(wCm,RCITY);
      total=parseFloat((rr.p*2+rb).toFixed(2))+parseFloat((pow*(200+tkan)).toFixed(2));
      if(c.rSystem==="elektryk"){
        rr=lookup(wCm,REL);
        total=parseFloat((rr.p*2+rb).toFixed(2))+parseFloat((pow*(200+tkan)).toFixed(2));
      }
      lines.push("Roleta rzymska "+rModel+" "+wCm+"\xd7"+hCm+"cm \xb7 "+pow+"m\xb2");
    }
    if(rb)lines.push("+ B\u0119benek 11 z\u0142");
  }else if(p.type==="shadow"){
    var wCm=par.wCm||0,hCm=par.hCm||0;
    if(!wCm||!hCm)return{total:0,lines:[],warn:null};
    var sg=c.sgrup||"C";
    var res=rsShadowLookup(sg,wCm,hCm);
    if(!res)return{total:0,lines:[],warn:"Wymiary poza zakresem cennika (maks. 300\xd7300 cm)."};
    total=res.price;
    lines.push("Roleta Shadow RM (Gr."+sg+") "+res.widthUsed+"\xd7"+res.heightUsed+"cm \u2192 "+res.price+" z\u0142");
    // Profil montażowy
    if(c.sprofil==="tak"){var pv=rsSuppLookup(RS_PROFIL,wCm);total+=pv;lines.push("+ Profil monta\u017cowy +"+pv+" z\u0142");}
    // Obciążnik
    if(c.sobcTyp&&c.sobcTyp!=="A"){
      var obcTbl={B:RS_OB_B,C:RS_OB_C,D:RS_OB_D}[c.sobcTyp];
      if(obcTbl){var ov=rsSuppLookup(obcTbl,wCm);total+=ov;lines.push("+ Obci\u0105\u017cnik Typ "+c.sobcTyp+" +"+ov+" z\u0142");}
    }else if(c.sobcTyp==="A"){
      lines.push("+ Obci\u0105\u017cnik Typ A (standardowy, w cenie)");
    }
    // Maskownica
    if(c.smask&&c.smask!=="brak"){var mv=RS_MASKS[c.smask]||0;if(mv){total+=mv;var mcl=RS_MASK_COLORS.find(function(x){return x.k===c.smaskKolor;});var mklbl=mcl?" ("+mcl.l+")":"";lines.push("+ Maskownica "+c.smask+mklbl+" +"+mv.toFixed(2)+" z\u0142");}}
    // Zestaw żyłkowy
    if(c.szylko==="tak"){total+=RS_ZESTAW_ZYLKOWY;lines.push("+ Zestaw do prowadzenia \u017cy\u0142kowego +"+RS_ZESTAW_ZYLKOWY.toFixed(2)+" z\u0142");}
    // Obciążnik łańcuszka
    if(c.slanc==="tak"){total+=RS_LANCUSZEK;lines.push("+ Ozdobny obci\u0105\u017cnik \u0142a\u0144cuszka +"+RS_LANCUSZEK.toFixed(2)+" z\u0142");}
    // Napęd
    if(c.smotor){
      var mot=RS_MOTORS.find(function(m){return m.id===c.smotor;});
      if(mot){total+=mot.price;lines.push("+ Nap\u0119d "+mot.label+" +"+mot.price+" z\u0142");}
    }
    // Pilot/centralka
    if(c.sremotes&&c.sremotes.length){
      c.sremotes.forEach(function(rid){
        var rem=RS_REMOTES.find(function(r){return r.id===rid;});
        if(rem){total+=rem.price;lines.push("+ "+rem.label+" +"+rem.price+" z\u0142");}
      });
    }
  }else if(p.type==="szyna"){
    var lenCm=par.len||0,arc=par.arc||0,pts=par.pts||0,qty=par.qty||1;
    if(!lenCm)return{total:0,lines:[],warn:null};
    var lenMb=lenCm/100;
    var baz;
    if(c.ks==="wave"){baz=parseFloat((lenMb*100).toFixed(2));}
    else baz=parseFloat((lenMb*80).toFixed(2));
    total=(baz+parseFloat((arc*100).toFixed(2))+parseFloat((pts*60).toFixed(2)))*qty;
    lines.push("KS "+(c.ks||"flex")+" "+lenCm+"cm ("+lenMb.toFixed(2)+"mb)"+(qty>1?" x"+qty:""));
    if(c.km==="sciana")warn="\u015acienny \u2014 dolicz uchwyty \u015bcienne.";
  }else if(p.type==="karnisz"){
    var lenK=par.len||0,pt=par.pt||0,arc=par.arc||0,qty=par.qty||1;
    if(!lenK)return{total:0,lines:[],warn:null};
    var st=c.km==="universal"?KUNIV:KSLIM;
    var rk=lookup(lenK,st);
    total=(rk.p+(KN[c.kn||"am75"]||0)+(KP[c.kp||"brak"]||0)+pt*210+arc*318)*qty;
    lines.push("Karnisz "+(c.km||"slim").toUpperCase()+" do "+rk.k+"cm"+(qty>1?" x"+qty:""));
  }
  return{total:total,lines:lines,warn:warn};
}

export function mg(a,b){return Object.assign({},a,b);}

export const IST ={padding:"16px 18px",fontSize:17,border:"1.5px solid var(--bd2)",borderRadius:10,background:"var(--bg)",color:"var(--t1)",width:"100%",minHeight:56,boxSizing:"border-box",transition:"border-color .15s"};


// ── INLINE EDIT COMPONENT ────────────────────────────────────────────────
export function InlineEdit(p){
  // p: {value, onSave, style, inputStyle}
  var es=useState(false),editing=es[0],setEditing=es[1];
  var vs=useState(p.value),val=vs[0],setVal=vs[1];
  React.useEffect(function(){setVal(p.value);},[p.value]);
  function confirm(){
    if(val.trim()) p.onSave(val.trim());
    setEditing(false);
  }
  if(editing){
    return ce("span",{style:{display:"inline-flex",alignItems:"center",gap:4}},
      ce("input",{autoFocus:true,value:val,
        onChange:function(ev){setVal(ev.target.value);},
        onKeyDown:function(ev){
          if(ev.key==="Enter")confirm();
          if(ev.key==="Escape"){setVal(p.value);setEditing(false);}
        },
        onBlur:confirm,
        style:Object.assign({},{fontSize:16,fontWeight:500,border:"none",borderBottom:"2px solid var(--gr)",outline:"none",background:"transparent",color:"var(--t1)",padding:"2px 4px",minWidth:120,maxWidth:"90vw"},p.inputStyle||{})
      })
    );
  }
  return ce("span",{style:Object.assign({},{display:"inline-flex",alignItems:"center",gap:5,cursor:"pointer"},p.style||{})},
    ce("span",{},p.value),
    ce("span",{
      onClick:function(ev){ev.stopPropagation();setEditing(true);},
      title:"Edytuj",
      style:{fontSize:18,color:"var(--t3)",opacity:0.75,lineHeight:1,padding:"6px 8px",borderRadius:8,
             border:"0.5px solid transparent",transition:"all .15s",cursor:"pointer",
             ":hover":{opacity:1}}
    },"\u270f\ufe0f")
  );
}

