export function formatPLN(n){return roundTo10(n).toLocaleString("pl-PL")+" zł";}
export function roundTo10(n){var r=n%10;return r<5?n-r:n+(10-r);}

export function getPDFOfferNumber(client){
  var now=new Date();
  var y=now.getFullYear();
  var m=String(now.getMonth()+1).padStart(2,"0");
  var d=String(now.getDate()).padStart(2,"0");
  var slug=(client.name||"").replace(/\s+/g,"-").slice(0,12);
  return "OF-"+y+m+d+"-"+slug;
}

export function buildOfferRows(client){
  // Returns [{lp, name, qty, unit, cenaJedn, total}]
  var rows=[];var lp=1;
  (client.rooms||[]).forEach(function(r){
    (r.windows||[]).forEach(function(w){
      (w.products||[]).forEach(function(p){
        var pfc=(p.type==="zaslona"||p.type==="firana")?mg(p,{panels:getPanelsForProd(p)}):p;
        var total=p.mp!=null?p.mp:(calc(pfc).total||0);
        if(!total)return;
        var lbl=(PROD_TYPES.find(function(t){return t.id===p.type;})||{label:p.type}).label;
        var prodLabel=p.type==="inny"?(p.innyNazwa||lbl):lbl;
        var desc=prodLabel+(p.fabName?" \u00b7 "+p.fabName:"")+" — "+r.name+" / "+w.name;
        var isKurtain=(p.type==="zaslona"||p.type==="firana");
        rows.push({lp:lp++,name:desc,qty:1,unit:isKurtain?"kpl.":"szt.",cenaJedn:total,total:total});
      });
    });
  });
  return rows;
}

export function buildFabricRows(client){
  // Group by fabric: {fabName, prod, brutto, width, metry}
  var map={};
  (client.rooms||[]).forEach(function(r){
    (r.windows||[]).forEach(function(w){
      (w.products||[]).forEach(function(p){
        if(p.type!=="zaslona"&&p.type!=="firana")return;
        var key=p.fabName||("reczna_"+p.fabMan);
        if(!map[key])map[key]={
          fabName:p.fabName||"Tkanina ręczna",
          prod:p.fabName?(FABRICS.find(function(f){return f.name===p.fabName;})||{prod:"-"}).prod:"-",
          brutto:p.fabMan||p.fabP||0,
          width:p.fabW||null,
          metry:0,rooms:[]
        };
        var panels=getPanelsForProd(p);
        var pForCalc=Object.assign({},p,{panels:panels});
        var res=calc(pForCalc);
        var metry=0;
        (res.lines||[]).forEach(function(l){
          var m=l.match(/([\d,.]+)mb/);if(m)metry+=parseFloat(m[1].replace(",","."));
        });
        map[key].metry+=metry;
        map[key].rooms.push(r.name+" / "+w.name+(p.note?(" ["+p.note+"]"):""));
      });
    });
  });
  return Object.values(map);
}

export function getPanelsForProd(prod){
  var pc=prod.c||{},par=prod.par||{},tw=par.wCm||0,sp=pc.split||"unequal";
  if(sp==="left") return [{side:"Zas\u0142ona lewa",w:tw}];
  if(sp==="right") return [{side:"Zas\u0142ona prawa",w:tw}];
  if(sp==="equal"){var h=Math.floor(tw/2);return [{side:"Zas\u0142ona lewa",w:h},{side:"Zas\u0142ona prawa",w:tw-h}];}
  var out=[];
  if(pc.leftW>0) out.push({side:"Zas\u0142ona lewa",w:pc.leftW});
  if(pc.rightW>0) out.push({side:"Zas\u0142ona prawa",w:pc.rightW});
  return out;
}

export function buildSewingRows(client){
  var rows=[];
  (client.rooms||[]).forEach(function(r){
    (r.windows||[]).forEach(function(w){
      (w.products||[]).forEach(function(prod){
        if(prod.type!=="zaslona"&&prod.type!=="firana")return;
        var panels=getPanelsForProd(prod);
        var prodForCalc=Object.assign({},prod,{panels:panels});
        var res=calc(prodForCalc);
        var metry=0;
        (res.lines||[]).forEach(function(l){
          var m=l.match(/([\d,.]+)mb/);if(m)metry+=parseFloat(m[1].replace(",","."));
        });
        var pc=prod.c||{},par=prod.par||{};
        var lbl=(PROD_TYPES.find(function(t){return t.id===prod.type;})||{label:prod.type}).label;
        var lblDisp=prod.type==="inny"?(prod.innyNazwa||lbl):lbl;
        var sz=(pc.sz==="wave"||pc.model==="wave")?"Wave":"Flex";
        var mars=pc.mars?(Math.round(+pc.mars*100))+"%":"150%";
        var split=pc.split||"unequal";
        var splitDesc="-";
        if(split==="left") splitDesc="Lewa sztuka";
        else if(split==="right") splitDesc="Prawa sztuka";
        else if(split==="equal"){var tw2=par.wCm||0;splitDesc="Komplet r\xf3wny ("+Math.floor(tw2/2)+" + "+Math.ceil(tw2/2)+" cm)";}
        else splitDesc="Komplet nier\xf3wny: L="+(pc.leftW||0)+"cm / P="+(pc.rightW||0)+"cm";
        var bottomMap={single:"Pojedynczy",double:"Podw\xf3jny",overlock:"Overlock",tape:"O\u0142owianka"};
        var bottomDesc=(bottomMap[pc.bottomType||"single"]||"Pojedynczy")+(pc.bottomSize?" "+pc.bottomSize+"cm":"");
        var fabObj=prod.fabName?FABRICS.find(function(f){return f.name===prod.fabName;}):null;
        rows.push({
          room:r.name,win:w.name,
          type:lblDisp,
          fabric:prod.fabName||(prod.fabMan?"r\u0119czna "+prod.fabMan+" z\u0142":"(brak)"),
          prod:fabObj?fabObj.prod:"",
          fabW:prod.fabW||prod.fabManW||"-",
          kolor:pc.kolor||"-",
          metry:metry,
          hCm:par.hCm||"-",
          wCm:par.wCm||"-",
          szStyle:sz+" "+mars,
          split:splitDesc,
          bottom:bottomDesc,
          glide:"Odst\u0119p "+(pc.glideGap||8)+" cm",
          leadInSides:pc.leadInSides?"tak":"nie",
          podszewka:pc.podszewka==="tak"?"TAK":"nie",
          note:prod.note||""
        });
      });
    });
  });
  return rows;
}


