export function generateOfferPDF(client,comm,montaz){
  montaz=montaz||0;
  comm=comm||0;
  var rows=buildOfferRows(client);
  if(!rows.length){alert("Brak wycenionych produktów.");return;}
  // Apply commission multiplier to each row
  if(comm>0){
    rows=rows.map(function(r){
      var newTotal=roundTo10(r.total*(1+comm));
      return Object.assign({},r,{total:newTotal,cenaJedn:newTotal});
    });
  }
  var total=rows.reduce(function(a,r){return a+r.total;},0);
  var netto=total/1.23;var vat=total-netto;
  var now=new Date();
  var dateStr=now.toLocaleDateString("pl-PL");
  var validStr=new Date(now.getTime()+30*24*3600*1000).toLocaleDateString("pl-PL");
  var offerNo=getPDFOfferNumber(client);

  var tableRows=rows.map(function(r){
    return [r.lp,r.name,r.qty,r.unit,
      r.cenaJedn.toFixed(2).replace(".",",")+" zł",
      (r.total/1.23).toFixed(2).replace(".",",")+" zł",
      "23%",
      (r.total-r.total/1.23).toFixed(2).replace(".",",")+" zł",
      r.total.toFixed(2).replace(".",",")+" zł"
    ];
  });
  tableRows.push(["","","","","<strong>Suma:</strong>",
    netto.toFixed(2).replace(".",",")+" zł","23%",
    vat.toFixed(2).replace(".",",")+" zł",
    "<strong>"+total.toFixed(2).replace(".",",")+" zł</strong>"
  ]);

  LOGO_PDF_G="data:image/png;base64,";
  BANNER_PDF_G="data:image/png;base64,";
  var html=`<!DOCTYPE html><html lang="pl"><head><meta charset="UTF-8"><title>${offerNo}</title>${pdfStyles()}</head><body>
  <div style="text-align:center;margin-bottom:8mm;line-height:0;"><img src="${BANNER_PDF_G}" style="width:520px;max-width:100%;height:auto;display:inline-block;" alt=""/></div>
  <div class="header" style="padding-top:2mm;">
    <div><img src="${LOGO_PDF_G}" style="height:54px;width:auto;" alt="Porter Design"/></div>
    <div style="text-align:right"><div style="font-size:18px;font-weight:700">Oferta nr ${offerNo}</div>
      <div style="font-size:9px;color:#6b6b66;margin-top:4px">Data wystawienia: ${dateStr} &nbsp;|&nbsp; Ważne do: ${validStr}</div>
    </div>
  </div>
  <div class="meta">
    <div class="meta-block"><h4>Sprzedawca</h4>
      <p><strong>${SELLER.name}</strong><br>${SELLER.addr}<br>${SELLER.city}<br>NIP: ${SELLER.nip}<br>Tel.: ${SELLER.tel}<br>E-mail: ${SELLER.email}<br>Konto: ${SELLER.bank}<br>${SELLER.bankName}</p>
    </div>
    <div class="meta-block"><h4>Nabywca</h4>
      <p><strong>${client.name}</strong><br>${client.addr||""}</p>
    </div>
  </div>
  ${makeTableHTML(["Lp.","Nazwa produktu / usługi","Ilość","Jedn.","Cena jedn. brutto","Wartość netto","Stawka VAT","Wartość VAT","Wartość brutto"],tableRows,"Pozycje")}
  <div class="sum-box"><span class="label">Do zapłaty</span><span class="amount">${total.toFixed(2).replace(".",",")} PLN</span></div>
  <div class="notes">Niniejszy dokument nie jest fakturą w rozumieniu ustawy z dnia 11 marca 2004 r. o podatku od towarów i usług.</div>
  <div class="sign-block">
    <div class="sign">Osoba uprawniona do wystawienia<br><strong>Paulina Porter</strong></div>
    <div class="sign">Osoba uprawniona do odbioru</div>
  </div>
  <div class="footer"><span>${SELLER.name} | ${SELLER.city}</span><span>Strona 1</span></div>
  </body></html>`;
  var montazVal=montaz>0?roundTo10(total*montaz):0;
  var offerNotes=window.prompt("Uwagi do oferty (opcjonalne):", "") || "";
  if(offerNotes===null)return;
  if(offerNotes) html=html.replace('<div class="notes">Niniejszy dokument nie jest fakturą','<div class="notes">'+ offerNotes +'<br><br>Niniejszy dokument nie jest fakturą');
  if(montazVal>0) html=html.replace('<div class="sum-box">','<div style="margin:4mm 0;padding:10px 14px;background:#f5ede0;border-radius:8px;display:flex;justify-content:space-between;"><span style="font-size:12px;color:#8B5E3C;">Monta\u017c dekoracji okiennych</span><span style="font-size:13px;font-weight:700;color:#8B5E3C;">'+montazVal.toFixed(2).replace(".",",")+' z\u0142</span></div><div class="sum-box">');
  openPDFWindow(html, offerNo);
}

// ── Suppliers for karnisze / szyny ─────────────────────────────────────────
export const KARNISZ_SUPPLIERS =[
  {key:"marcin_dekor", label:"Marcin Dekor"},
  {key:"forest_polska",label:"Forest Polska, ul. Poloneza 89, 02-826 Warszawa"}
];

export function buildKarniszRows(client){
  var rows=[];
  (client.rooms||[]).forEach(function(r){
    (r.windows||[]).forEach(function(w){
      (w.products||[]).forEach(function(p){
        if(p.type!=="karnisz"&&p.type!=="szyna")return;
        var pc=p.c||{},par=p.par||{};
        var typLabel=p.type==="karnisz"?"Karnisz elektryczny "+(pc.km||"slim").toUpperCase():"Szyna KS "+(pc.ks||"flex");
        var len=par.len||0;
        var res=calc(p);
        rows.push({
          room:r.name,
          win:w.name,
          type:typLabel,
          len:len,
          qty:par.qty||1,
          arc:par.arc||0,
          arcDepth:par.arcDepth||null,
          pts:par.pt||par.pts||0,
          motorSide:p.type==="karnisz"?(pc.motorSide||"lewo"):null,
          motorType:p.type==="karnisz"?(pc.motorType||"kurtyna"):null,
          supplier:p.karniszSupplier||"",
          total:res.total||0,
          lines:(res.lines||[]).join("; ")
        });
      });
    });
  });
  return rows;
}

export function generateKarniszOrderPDF(client){
  var rows=buildKarniszRows(client);
  if(!rows.length){alert("Brak karniszów / szyn do zamówienia.");return;}
  var now=new Date();var dateStr=now.toLocaleDateString("pl-PL");

  // Collect rows without a supplier assigned
  var pending=rows.filter(function(r){return !r.supplier;});

  function proceedWithPDF(){
    // Group by supplier
    var bySupplier={};
    KARNISZ_SUPPLIERS.forEach(function(s){bySupplier[s.key]=[];});
    rows.forEach(function(r){
      var key=(r.supplier&&bySupplier[r.supplier]!==undefined)?r.supplier:"marcin_dekor";
      bySupplier[key].push(r);
    });

  var activeSups=KARNISZ_SUPPLIERS.filter(function(s){return bySupplier[s.key].length>0;});
  if(!activeSups.length){alert("Brak pozycji.");return;}

  var supplierSections=activeSups.map(function(sup,si){
    var supRows=bySupplier[sup.key];
    var tableRows=supRows.map(function(r){
      var motorDesc=r.motorSide?(r.motorSide.charAt(0).toUpperCase()+r.motorSide.slice(1))+(r.motorType?" / "+(r.motorType.charAt(0).toUpperCase()+r.motorType.slice(1)):""):"–";
      return [
        r.room+" / "+r.win,
        r.type,
        r.len?r.len+"cm":"-",
        r.qty>1?r.qty+" szt.":"1 szt.",
        r.arc?r.arc+" mb":"–",
        r.arcDepth?r.arcDepth+" cm":"–",
        r.pts?r.pts+" szt.":"–",
        motorDesc,
        r.total>0?r.total.toFixed(2).replace(".",",")+" zł":"–"
      ];
    });

    var tableHTML=makeTableHTML(
      ["Pom. / Okno","Typ","D\u0142ugo\u015b\u0107","Ilo\u015b\u0107","Gi\u0119cie \u0142uk","G\u0142\u0119b. \u0142uku","Gi\u0119cie pkt","Silnik / Typ","Warto\u015b\u0107"],
      tableRows,
      "Pozycje do zam\xf3wienia"
    );

    var pageBreak=si>0?"<div style=\"page-break-before:always;padding-top:10mm;\"></div>":"";

    return pageBreak+"\n    <div class=\"supplier-header\">\n      <div class=\"supplier-name\">"+sup.label+"</div>\n      <div class=\"supplier-meta\">Zamawiaj\u0105cy: <strong>"+SELLER.name+"</strong>  |  Tel.: "+SELLER.tel+"  |  E-mail: "+SELLER.email+"</div>\n      <div class=\"supplier-meta\">Klient ko\u0144cowy: <strong>"+client.name+"</strong>"+(client.addr?" \u2014 "+client.addr:"")+"  |  Data: "+dateStr+"</div>\n    </div>\n    "+tableHTML+"\n    <div class=\"notes\" style=\"margin-top:4mm\">Termin dostawy: _________________ &nbsp;&nbsp;&nbsp; Forma p\u0142atno\u015bci: _________________ &nbsp;&nbsp;&nbsp; Podpis: _________________</div>\n    <div class=\"sign-block\" style=\"margin-top:8mm\">\n      <div class=\"sign\">Zamawiaj\u0105cy<br><strong>Paulina Porter</strong></div>\n      <div class=\"sign\">Dostawca \u2014 potwierdzenie</div>\n    </div>";
  }).join("");

  var extraStyles="\n    .supplier-header{background:#f2f2ef;border:0.5px solid #c8c8c4;border-radius:4px;padding:8px 12px;margin-bottom:5mm;}\n    .supplier-name{font-size:14px;font-weight:700;color:#1a1a18;margin-bottom:3px;letter-spacing:0.03em;}\n    .supplier-meta{font-size:9px;color:#6b6b66;margin-top:2px;}\n  ";

  var html="<!DOCTYPE html><html lang=\"pl\"><head><meta charset=\"UTF-8\"><title>Zam\xf3wienie karnisz\xf3w \u2014 "+client.name+"</title>"+pdfStyles().replace("</style>",extraStyles+"</style>")+"</head><body>"
    +"<div class=\"header\"><div><div class=\"logo-text\">PORTER<br>DESIGN</div><div class=\"logo-sub\">Dekoracje okienne</div></div>"
    +"<div style=\"text-align:right\"><div style=\"font-size:18px;font-weight:700\">Zam\xf3wienie karnisz\xf3w / szyn</div>"
    +"<div style=\"font-size:9px;color:#6b6b66;margin-top:4px\">Klient: <strong>"+client.name+"</strong> &nbsp;|&nbsp; Data: "+dateStr+" &nbsp;|&nbsp; Dostawc\xf3w: "+activeSups.length+"</div></div></div>"
    +supplierSections
    +"<div class=\"footer\" style=\"margin-top:8mm\"><span>"+SELLER.name+" | "+SELLER.city+"</span><span>Generowano: "+dateStr+"</span></div>"
    +"</body></html>";

  openPDFWindow(html,"zamowienie-karnisz");
  } // end proceedWithPDF

  // If all rows already have suppliers, go straight to PDF
  if(!pending.length){proceedWithPDF();return;}

  // Build a touch-friendly dialog to assign supplier per unassigned item
  var dlg=document.createElement("dialog");
  dlg.style.cssText="border:none;border-radius:14px;padding:24px 20px;max-width:400px;width:92%;box-shadow:0 8px 40px rgba(0,0,0,0.22);font-family:inherit;";

  var pidx=0;
  function showSupplierPick(){
    if(pidx>=pending.length){dlg.close();document.body.removeChild(dlg);proceedWithPDF();return;}
    var r=pending[pidx];
    var btns=KARNISZ_SUPPLIERS.map(function(s){
      return '<button data-key="'+s.key+'" style="display:block;width:100%;padding:14px 16px;border-radius:8px;border:1.5px solid #c8c8c4;background:#fff;font-size:14px;font-weight:600;cursor:pointer;text-align:left;margin-bottom:10px;">'+s.label+'</button>';
    }).join('');
    dlg.innerHTML='<div style="font-size:12px;color:#888;margin-bottom:6px;font-weight:600;letter-spacing:0.04em;text-transform:uppercase;">Dostawca ('+(pidx+1)+'/'+pending.length+')</div>'
      +'<div style="font-weight:700;font-size:15px;margin-bottom:4px">'+r.room+' / '+r.win+'</div>'
      +'<div style="font-size:13px;color:#555;margin-bottom:20px">'+r.type+(r.len?' — '+r.len+' cm':'')+'</div>'
      +btns
      +'<button data-key="cancel" style="display:block;width:100%;padding:10px;border-radius:8px;border:none;background:none;font-size:13px;color:#888;cursor:pointer;">Anuluj</button>';
    dlg.querySelectorAll("button").forEach(function(btn){
      btn.addEventListener("click",function(){
        var key=btn.getAttribute("data-key");
        if(key==="cancel"){dlg.close();document.body.removeChild(dlg);return;}
        r.supplier=key;
        pidx++;
        showSupplierPick();
      });
    });
  }
  document.body.appendChild(dlg);
  dlg.showModal();
  showSupplierPick();
}


